code = """import json

# Load symbol info
stock_info_list = locals()['var_function-call-8149250835378589217']
# Load volume info
volume_info_list = locals()['var_function-call-10104720921898228878']

# Create a dictionary for quick lookup of description
desc_map = {item['Symbol']: item['Company Description'] for item in stock_info_list}

# Process volume info
results = []
for item in volume_info_list:
    sym = item['Symbol']
    vol = float(item['AvgVol'])
    desc = desc_map.get(sym, "Unknown")
    
    # Extract name
    # Heuristics
    # Split by common keywords
    keywords = [" specializes", " provides", " is", " offers", " harnesses", " dedicated", " based"]
    name = desc
    min_idx = len(desc)
    for kw in keywords:
        idx = desc.find(kw)
        if idx != -1 and idx < min_idx:
            min_idx = idx
    
    if min_idx < len(desc):
        name = desc[:min_idx].strip()
        # Remove trailing comma if any
        if name.endswith(','):
            name = name[:-1]
    
    results.append({
        "Company Name": name,
        "Symbol": sym,
        "Average Daily Trading Volume (2008)": vol
    })

print("__RESULT__:")
print(json.dumps(results, indent=2))"""

